import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function KLineChart() {
    const d3Container = useRef(null);

    useEffect(() => {
        let svg;
        let width = d3Container.current.clientWidth;
        let height = d3Container.current.clientHeight;
        let margin = { top: 24, right: 24, bottom: 32, left: 56 };
        let chartW = width - margin.left - margin.right;
        let chartH = height - margin.top - margin.bottom;

        // 清空
        d3.select(d3Container.current).selectAll('*').remove();

        // 取得資料
        axios.get('http://localhost:3001/api/kline').then(res => {
            const data = res.data.map(d => ({
                ...d,
                date: d3.isoParse(d.timestamp || d.date || d.Date),
                open: +d.Open,
                high: +d.High,
                low: +d.Low,
                close: +d.Close,
                volume: +d.Volume
            })).filter(d => d.date);
            if (data.length === 0) return;

            // X, Y scale
            let x = d3.scaleBand()
                .domain(data.map(d => d.date))
                .range([0, chartW])
                .padding(0.3);
            let y = d3.scaleLinear()
                .domain([d3.min(data, d => d.low), d3.max(data, d => d.high)])
                .nice()
                .range([chartH, 0]);

            // SVG
            svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height);

            const g = svg.append('g')
                .attr('transform', `translate(${margin.left},${margin.top})`);

            // 畫K棒和影線的函數（可重繪）
            function drawKline(x, y) {
                g.selectAll('.kbar').remove();
                g.selectAll('.kline').remove();
                g.selectAll('.kbar')
                    .data(data)
                    .enter()
                    .append('rect')
                    .attr('class', 'kbar')
                    .attr('x', d => x(d.date))
                    .attr('y', d => y(Math.max(d.open, d.close)))
                    .attr('width', x.bandwidth())
                    .attr('height', d => Math.max(1, Math.abs(y(d.open) - y(d.close))))
                    .attr('fill', d => d.close >= d.open ? '#26ff8a' : '#ff3c3c')
                    .attr('stroke', '#222');
                g.selectAll('.kline')
                    .data(data)
                    .enter()
                    .append('line')
                    .attr('class', 'kline')
                    .attr('x1', d => x(d.date) + x.bandwidth() / 2)
                    .attr('x2', d => x(d.date) + x.bandwidth() / 2)
                    .attr('y1', d => y(d.high))
                    .attr('y2', d => y(d.low))
                    .attr('stroke', d => d.close >= d.open ? '#26ff8a' : '#ff3c3c')
                    .attr('stroke-width', 2)
                    .attr('opacity', 0.8);
            }

            // 畫軸的函數
            function drawAxis(x, y) {
                g.selectAll('.x-axis').remove();
                g.selectAll('.y-axis').remove();
                g.append('g')
                    .attr('class', 'x-axis')
                    .attr('transform', `translate(0,${chartH})`)
                    .call(d3.axisBottom(x).tickFormat(d3.timeFormat('%Y-%m-%d')).tickValues(x.domain().filter((d, i) => i % Math.ceil(data.length / 10) === 0)))
                    .selectAll('text')
                    .attr('transform', 'rotate(-30)')
                    .style('text-anchor', 'end');
                g.append('g')
                    .attr('class', 'y-axis')
                    .call(d3.axisLeft(y));
            }

            drawKline(x, y);
            drawAxis(x, y);

            // Zoom/drag
            const zoom = d3.zoom()
                .scaleExtent([1, 20])
                .translateExtent([[0, 0], [chartW, chartH]])
                .extent([[0, 0], [chartW, chartH]])
                .on('zoom', (event) => {
                    const t = event.transform;
                    const zx = t.rescaleX(d3.scaleLinear().domain([0, data.length - 1]).range([0, chartW]));
                    // 重新計算x
                    const newDomain = zx.domain().map(Math.round);
                    const shown = data.slice(newDomain[0], newDomain[1] + 1);
                    let xz = d3.scaleBand()
                        .domain(shown.map(d => d.date))
                        .range([0, chartW])
                        .padding(0.3);
                    drawKline(xz, y);
                    drawAxis(xz, y);
                    // 十字線與tooltip也要更新
                });
            svg.call(zoom);

            // 十字線與tooltip
            const tooltip = d3.select(d3Container.current)
                .append('div')
                .attr('class', 'k-tooltip')
                .style('position', 'absolute')
                .style('pointer-events', 'none')
                .style('background', '#222')
                .style('color', '#fff')
                .style('padding', '8px 12px')
                .style('border-radius', '8px')
                .style('font-size', '14px')
                .style('opacity', 0);
            svg.on('mousemove', function (event) {
                const [mx, my] = d3.pointer(event);
                const tx = mx - margin.left;
                if (tx < 0 || tx > chartW) { tooltip.style('opacity', 0); return; }
                const idx = Math.floor(tx / chartW * data.length);
                const d = data[idx];
                if (!d) { tooltip.style('opacity', 0); return; }
                // 十字線
                g.selectAll('.crosshair').remove();
                g.append('line')
                    .attr('class', 'crosshair')
                    .attr('x1', x(d.date) + x.bandwidth() / 2)
                    .attr('x2', x(d.date) + x.bandwidth() / 2)
                    .attr('y1', 0)
                    .attr('y2', chartH)
                    .attr('stroke', '#00c3ff')
                    .attr('stroke-width', 1.5)
                    .attr('stroke-dasharray', '4 2');
                g.append('line')
                    .attr('class', 'crosshair')
                    .attr('x1', 0)
                    .attr('x2', chartW)
                    .attr('y1', y(d.close))
                    .attr('y2', y(d.close))
                    .attr('stroke', '#00c3ff')
                    .attr('stroke-width', 1.5)
                    .attr('stroke-dasharray', '4 2');
                // Tooltip
                tooltip.style('opacity', 1)
                    .style('left', `${mx + 20}px`)
                    .style('top', `${my + 20}px`)
                    .html(`日期: ${d3.timeFormat('%Y-%m-%d')(d.date)}<br/>開: ${d.open}<br/>高: ${d.high}<br/>低: ${d.low}<br/>收: ${d.close}<br/>量: ${d.volume}`);
            });
            svg.on('mouseleave', function () {
                g.selectAll('.crosshair').remove();
                tooltip.style('opacity', 0);
            });
        });
    }, []);

    return (
        <div style={{ position: 'relative' }}>
            <h2 style={{ color: '#00c3ff' }}>K線圖 (可互動)</h2>
            <div ref={d3Container} style={{ width: '100%', height: '500px', background: '#181a1b', borderRadius: '12px', boxShadow: '0 2px 12px #00c3ff22', overflow: 'hidden', position: 'relative' }}>
                {/* D3 K線圖會渲染在這裡 */}
            </div>
        </div>
    );
}

export default KLineChart;
